1	//! Slice-2.5 userland bootstrap: minimal TTBR0 setup + two EL0 stub tasks
2	//! that exchange IPC messages.
3	//!
4	//! Builds a 4-level page-table walk in static `.bss` storage that maps
5	//! five user pages: one code page per stub plus one stack page per stub.
6	//!   - `USER_CODE_VA_A` → physical `USER_CODE_PAGE_A` filled with the
7	//!     sender stub (`_user_stub_a_start..._user_stub_a_end`). RO + EL0 X.
8	//!   - `USER_CODE_VA_B` → physical `USER_CODE_PAGE_B` filled with the echo
9	//!     stub (`_user_stub_b_start..._user_stub_b_end`). RO + EL0 X.
10	//!   - `USER_STACK_VA_A` / `USER_STACK_VA_B` → two kernel-owned pages used
11	//!     as each stub's EL0 stack. RW + EL0, no execute.
12	//!
13	//! Each stub also gets its own privilege-table slot (16 = A, 17 = B) with
14	//! `trap_mask = SRV_T` and `ipc_to` cross-linking A↔B — that's what lets
15	//! the slice-2.5 IPC trap-mask and `ipc_to` enforcement permit the
16	//! ping-pong while denying any other endpoint.
17	//!
18	//! After populating each stub's process slot and priv slot, the bootstrap
19	//! enqueues both into the priority-banded run queue. The caller
20	//! (`kmain`) then transfers control to the scheduler via `proc::sched::run`.
21	//!
22	//! Phase 3's VM server replaces this entire file with proper per-process
23	//! address spaces, ELF loading, and copy-on-write semantics.
24	
25	use core::cell::UnsafeCell;
26	use core::sync::atomic::Ordering;
27	
28	use minix4_kernel_shared::callnr::{KERNEL_CALL, SYS_GETINFO};
29	use minix4_kernel_shared::com::{RS_PROC_NR, SYSTEM, boot_endpoint};
30	use minix4_kernel_shared::{PrivId, ProcNr};
31	
32	use crate::arch::aarch64::limine::kernel_va_to_pa;
33	use crate::arch::aarch64::mmu::{
34	    self, ATTR_IDX_NORMAL, PAGE_SIZE, PTE_AF, PTE_AP_RO_EL0, PTE_AP_RW_EL0, PTE_PXN,
35	    PTE_SH_INNER, PTE_UXN, PageTable, pte_attr_idx,
36	};
37	use crate::proc::bitmap::{set_call_bit, set_sys_bit};
38	use crate::proc::flags::{BILLABLE, PREEMPTIBLE, SRV_T, SYS_PROC, USR_T};
39	use crate::proc::sched;
40	use crate::proc::table::{priv_slot_mut, proc_index, proc_slot_mut, proc_table_ref};
41	use crate::proc::{Priv, Proc};
42	
43	// ----- EL0 virtual addresses ------------------------------------------------
44	
45	/// VA at which stub A's code page is mapped.
46	pub const USER_CODE_VA_A: u64 = 0x0040_0000; // 4 MiB
47	/// VA at which stub A's stack page is mapped.
48	pub const USER_STACK_VA_A: u64 = 0x0080_0000; // 8 MiB
49	
50	/// VA at which stub B's code page is mapped (one 4 KiB page above A).
51	/// Same 2 MiB L2 slot as A, so the L3_CODE table is shared.
52	pub const USER_CODE_VA_B: u64 = 0x0041_0000;
53	/// VA at which stub B's stack page is mapped. Same 2 MiB L2 slot as A's
54	/// stack, so the L3_STACK table is shared.
55	pub const USER_STACK_VA_B: u64 = 0x0081_0000;
56	
57	/// VA at which stub C's code page is mapped (one 4 KiB page above B).
58	pub const USER_CODE_VA_C: u64 = 0x0042_0000;
59	/// VA at which stub C's stack page is mapped. Same L2/L3 tables as A/B.
60	pub const USER_STACK_VA_C: u64 = 0x0082_0000;
61	
62	/// First proc-table slot beyond the boot image — `ProcNr(11)`. Boot procs
63	/// occupy `0..=INIT_PROC_NR` (i.e. `0..=10`).
64	const STUB_A_PROC_NR: ProcNr = ProcNr::new(11);
65	/// Second stub slot, just after A.
66	const STUB_B_PROC_NR: ProcNr = ProcNr::new(12);
67	/// Slice-2.6 kernel-call client. Slot 13 — one past the slice-2.5 pair.
68	const STUB_C_PROC_NR: ProcNr = ProcNr::new(13);
69	
70	/// Privilege-table slots for the three stubs. Boot image uses 0..=15;
71	/// 16, 17, and 18 are the first free entries.
72	const STUB_A_PRIV_ID: PrivId = PrivId::new(16);
73	const STUB_B_PRIV_ID: PrivId = PrivId::new(17);
74	const STUB_C_PRIV_ID: PrivId = PrivId::new(18);
75	
76	// SPSR_EL1 to install on each stub's `eret`. Compared to slice 2.3's
77	// `0x3C0` (all four DAIF bits masked), we clear bit 7 (`I`) so that IRQs
78	// are unmasked at EL0 — that's the whole point of slice 2.4. Bits set:
79	//   - bit 9 (D) = 1     // debug mask
80	//   - bit 8 (A) = 1     // SError mask
81	//   - bit 7 (I) = 0     // IRQs ENABLED at EL0
82	//   - bit 6 (F) = 1     // FIQ mask (we don't handle FIQ in slice 2.4)
83	//   - bits 3:0 (M)     = 0 // EL0t
84	const STUB_SPSR_EL0: u64 = 0x340;
85	
86	// ----- Static storage ------------------------------------------------------
87	
88	/// 4 KiB-aligned raw byte page, used for the EL0 stubs' code and stacks.
89	#[repr(C, align(4096))]
90	struct UserPage(UnsafeCell<[u8; PAGE_SIZE]>);
91	// SAFETY: single-threaded boot context; no concurrent access. Same invariant
92	// documented on `ProcStorage` / `PrivStorage` in `proc::table`.
93	unsafe impl Sync for UserPage {}
94	
95	impl UserPage {
96	    const EMPTY: Self = Self(UnsafeCell::new([0; PAGE_SIZE]));
97	}
98	
99	#[repr(transparent)]
100	struct PtSlot(UnsafeCell<PageTable>);
101	// SAFETY: single-threaded boot; mutation is confined to `userland_bootstrap`.
102	unsafe impl Sync for PtSlot {}
103	
104	static L0_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
105	static L1_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
106	static L2_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
107	static L3_CODE_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
108	static L3_STACK_TABLE: PtSlot = PtSlot(UnsafeCell::new(PageTable::EMPTY));
109	
110	/// Per-task code pages — A is the sender stub, B is the echo stub, C is the
111	/// kernel-call client introduced in slice 2.6.
112	static USER_CODE_PAGE_A: UserPage = UserPage::EMPTY;
113	static USER_CODE_PAGE_B: UserPage = UserPage::EMPTY;
114	static USER_CODE_PAGE_C: UserPage = UserPage::EMPTY;
115	/// Per-task stack pages.
116	static USER_STACK_PAGE_A: UserPage = UserPage::EMPTY;
117	static USER_STACK_PAGE_B: UserPage = UserPage::EMPTY;
118	static USER_STACK_PAGE_C: UserPage = UserPage::EMPTY;
119	
120	// ----- EL0 stub blobs (linked into the kernel image by `user_stub.S`) ------
121	
122	unsafe extern "C" {
123	    static _user_stub_a_start: u8;
124	    static _user_stub_a_end: u8;
125	    static _user_stub_b_start: u8;
126	    static _user_stub_b_end: u8;
127	    static _user_stub_c_start: u8;
128	    static _user_stub_c_end: u8;
129	}
130	
131	// ----- Bootstrap ----------------------------------------------------------
132	
133	/// Wire up TTBR0 mappings, copy the EL0 stub into its shared code page,
134	/// populate both stub proc slots, and enqueue them on the run queue.
135	///
136	/// SAFETY: must be called exactly once from `kmain` before any EL0 code
137	/// runs. Single-threaded boot context; no other reference into the static
138	/// page-table arena, user pages, or `PROC_TABLE[STUB_*_PROC_NR]` may exist
139	/// concurrently.
140	pub unsafe fn userland_bootstrap() {
141	    // 1. Verify Limine left MAIR_EL1's index 0 as Normal WB and that
142	    //    TCR_EL1's TTBR0-side fields match what `activate_user_ttbr0`
143	    //    expects.
144	    mmu::assert_mair_normal_wb();
145	    mmu::assert_tcr_el1_ttbr0_ready();
146	
147	    // 2. Resolve physical addresses for our static storage.
148	    let l0_pa = kernel_pa_of(L0_TABLE.0.get() as u64);
149	    let l1_pa = kernel_pa_of(L1_TABLE.0.get() as u64);
150	    let l2_pa = kernel_pa_of(L2_TABLE.0.get() as u64);
151	    let l3_code_pa = kernel_pa_of(L3_CODE_TABLE.0.get() as u64);
152	    let l3_stack_pa = kernel_pa_of(L3_STACK_TABLE.0.get() as u64);
153	    let code_a_pa = kernel_pa_of(USER_CODE_PAGE_A.0.get() as u64);
154	    let code_b_pa = kernel_pa_of(USER_CODE_PAGE_B.0.get() as u64);
155	    let code_c_pa = kernel_pa_of(USER_CODE_PAGE_C.0.get() as u64);
156	    let stack_a_pa = kernel_pa_of(USER_STACK_PAGE_A.0.get() as u64);
157	    let stack_b_pa = kernel_pa_of(USER_STACK_PAGE_B.0.get() as u64);
158	    let stack_c_pa = kernel_pa_of(USER_STACK_PAGE_C.0.get() as u64);
159	
160	    // 3. Build the user mappings. Each stub now has its own physical
161	    //    code page so A (sender) and B (echo) can run distinct programs.
162	    //    The four VAs split into two L2 slots (one for the 0x40_xxxx code
163	    //    pair, one for the 0x80_xxxx stack pair), each backed by a single
164	    //    L3 table.
165	    let code_attrs =
166	        PTE_AF | PTE_SH_INNER | PTE_AP_RO_EL0 | PTE_PXN | pte_attr_idx(ATTR_IDX_NORMAL);
167	    let stack_attrs = PTE_AF
168	        | PTE_SH_INNER
169	        | PTE_AP_RW_EL0
170	        | PTE_PXN
171	        | PTE_UXN
172	        | pte_attr_idx(ATTR_IDX_NORMAL);
173	
174	    // SAFETY: single-threaded boot; no other references into the table
175	    // storage exist. PAs were resolved above.
176	    unsafe {
177	        let l0 = &mut *L0_TABLE.0.get();
178	        let l1 = &mut *L1_TABLE.0.get();
179	        let l2 = &mut *L2_TABLE.0.get();
180	        let l3_code = &mut *L3_CODE_TABLE.0.get();
181	        let l3_stack = &mut *L3_STACK_TABLE.0.get();
182	
183	        mmu::map_4k(
184	            l0, l1, l2, l3_code,
185	            l1_pa, l2_pa, l3_code_pa,
186	            USER_CODE_VA_A, code_a_pa, code_attrs,
187	        );
188	        mmu::map_4k(
189	            l0, l1, l2, l3_code,
190	            l1_pa, l2_pa, l3_code_pa,
191	            USER_CODE_VA_B, code_b_pa, code_attrs,
192	        );
193	        mmu::map_4k(
194	            l0, l1, l2, l3_code,
195	            l1_pa, l2_pa, l3_code_pa,
196	            USER_CODE_VA_C, code_c_pa, code_attrs,
197	        );
198	        mmu::map_4k(
199	            l0, l1, l2, l3_stack,
200	            l1_pa, l2_pa, l3_stack_pa,
201	            USER_STACK_VA_A, stack_a_pa, stack_attrs,
202	        );
203	        mmu::map_4k(
204	            l0, l1, l2, l3_stack,
205	            l1_pa, l2_pa, l3_stack_pa,
206	            USER_STACK_VA_B, stack_b_pa, stack_attrs,
207	        );
208	        mmu::map_4k(
209	            l0, l1, l2, l3_stack,
210	            l1_pa, l2_pa, l3_stack_pa,
211	            USER_STACK_VA_C, stack_c_pa, stack_attrs,
212	        );
213	    }
214	
215	    // 4. Copy each EL0 stub into its own code page; clean+invalidate so
216	    //    the upcoming EL0 fetches see the new bytes.
217	    // SAFETY: `_user_stub_*_start/end` are rodata symbols inside the
218	    // kernel image; start ≤ end is enforced by the linker.
219	    unsafe {
220	        copy_stub_into_page(
221	            &USER_CODE_PAGE_A,
222	            &_user_stub_a_start,
223	            &_user_stub_a_end,
224	        );
225	        copy_stub_into_page(
226	            &USER_CODE_PAGE_B,
227	            &_user_stub_b_start,
228	            &_user_stub_b_end,
229	        );
230	        copy_stub_into_page(
231	            &USER_CODE_PAGE_C,
232	            &_user_stub_c_start,
233	            &_user_stub_c_end,
234	        );
235	    }
236	
237	    // 5. Install TTBR0 with our L0 root.
238	    // SAFETY: DAIF is still masked from boot.
239	    unsafe { mmu::activate_user_ttbr0(l0_pa) };
240	
241	    // 6. Populate each stub's proc slot. Borrows are sequential, never
242	    //    overlapping.
243	    // SAFETY: single-threaded boot; sequential mutable borrows.
244	    unsafe {
245	        let pa = proc_slot_mut(STUB_A_PROC_NR).expect("STUB_A_PROC_NR within table");
246	        populate_stub_slot(
247	            pa,
248	            STUB_A_PROC_NR,
249	            STUB_A_PRIV_ID,
250	            b'A',
251	            USER_CODE_VA_A,
252	            USER_STACK_VA_A + PAGE_SIZE as u64,
253	        );
254	    }
255	    // SAFETY: same — A's borrow has been dropped before we take B.
256	    unsafe {
257	        let pb = proc_slot_mut(STUB_B_PROC_NR).expect("STUB_B_PROC_NR within table");
258	        populate_stub_slot(
259	            pb,
260	            STUB_B_PROC_NR,
261	            STUB_B_PRIV_ID,
262	            b'B',
263	            USER_CODE_VA_B,
264	            USER_STACK_VA_B + PAGE_SIZE as u64,
265	        );
266	    }
267	
268	    // SAFETY: same — B's borrow has been dropped before we take C.
269	    unsafe {
270	        let pc = proc_slot_mut(STUB_C_PROC_NR).expect("STUB_C_PROC_NR within table");
271	        populate_stub_slot(
272	            pc,
273	            STUB_C_PROC_NR,
274	            STUB_C_PRIV_ID,
275	            b'C',
276	            USER_CODE_VA_C,
277	            USER_STACK_VA_C + PAGE_SIZE as u64,
278	        );
279	    }
280	
281	    // 7. Install priv slots for the three stubs. A↔B carry the slice-2.5
282	    //    ping-pong (SRV_T + cross-linked ipc_to); C is the slice-2.6
283	    //    kernel-call client (USR_T + ipc_to→SYSTEM + k_call_mask→SYS_GETINFO).
284	    // SAFETY: single-threaded boot; install_stub_privs only touches
285	    // priv-table slots 16, 17, and 18 sequentially.
286	    unsafe { install_stub_privs() };
287	
288	    // 8. Enqueue all three on the scheduler. They run in FIFO order within
289	    //    the same priority band (SRV_Q); the timer preempts after one
290	    //    quantum each.
291	    // SAFETY: single-threaded boot; sched module's invariants documented
292	    // on `enqueue`. No other PROC_TABLE / RUNQ borrows live.
293	    unsafe {
294	        sched::enqueue(STUB_A_PROC_NR);
295	        sched::enqueue(STUB_B_PROC_NR);
296	        sched::enqueue(STUB_C_PROC_NR);
297	    }
298	}
299	
300	/// Copy bytes from `[stub_start, stub_end)` into `page` and flush the
301	/// I-cache for the range so the upcoming EL0 fetch sees the new code.
302	///
303	/// SAFETY: `stub_start` / `stub_end` must be a valid contiguous range in
304	/// the kernel image; `page` must be a 4 KiB-aligned BSS page we hold
305	/// exclusively.
306	unsafe fn copy_stub_into_page(page: &UserPage, stub_start: *const u8, stub_end: *const u8) {
307	    // SAFETY: `stub_end - stub_start` is non-negative by linker layout.
308	    let len = unsafe { stub_end.offset_from(stub_start) } as usize;
309	    assert!(len > 0 && len <= PAGE_SIZE);
310	    // SAFETY: caller's invariants — page is a 4 KiB-aligned writable BSS
311	    // page and we hold the only mutable reference (single-threaded boot).
312	    unsafe {
313	        let dst = page.0.get() as *mut u8;
314	        core::ptr::copy_nonoverlapping(stub_start, dst, len);
315	        mmu::flush_icache_range(page.0.get() as u64, len);
316	    }
317	}
318	
319	/// Install priv slots for the three slice-2.5/2.6 stubs. Must run after
320	/// `proc::init` (so slots 0..=15 are populated) and before
321	/// `sched::enqueue` (so the IPC path sees the priv_id when the stubs
322	/// first SVC).
323	///
324	/// SAFETY: single-threaded boot; touches priv-table slots 16, 17, and 18
325	/// sequentially.
326	unsafe fn install_stub_privs() {
327	    // SAFETY: sequential mutable borrow.
328	    unsafe {
329	        install_one_stub_priv(
330	            STUB_A_PRIV_ID,
331	            STUB_A_PROC_NR,
332	            STUB_B_PRIV_ID,
333	        );
334	    }
335	    // SAFETY: A's borrow has been dropped before we take B's slot.
336	    unsafe {
337	        install_one_stub_priv(
338	            STUB_B_PRIV_ID,
339	            STUB_B_PROC_NR,
340	            STUB_A_PRIV_ID,
341	        );
342	    }
343	    // SAFETY: B's borrow has been dropped before we take C's slot.
344	    unsafe {
345	        install_stub_c_priv();
346	    }
347	}
348	
349	/// Install stub C's priv slot (slice 2.6). Differs from the A/B helper:
350	/// trap_mask = USR_T (only SENDREC permitted, matches the eventual
351	/// user-process pattern), ipc_to is opened just to SYSTEM's priv slot,
352	/// and k_call_mask is opened just to SYS_GETINFO.
353	///
354	/// SAFETY: single-threaded boot; mutates only priv-table slot
355	/// `STUB_C_PRIV_ID`.
356	unsafe fn install_stub_c_priv() {
357	    // Resolve SYSTEM's priv_id at runtime — `proc::init` set it from
358	    // IMAGE, and hard-coding the slot index here would silently rot if
359	    // the IMAGE table is ever reordered.
360	    let system_priv_id = {
361	        // SAFETY: read-only snapshot; no mutable borrow into PROC_TABLE
362	        // is live at this point.
363	        let table = unsafe { proc_table_ref() };
364	        let idx = proc_index(SYSTEM).expect("SYSTEM in proc table");
365	        table[idx].priv_id.expect("SYSTEM priv populated by proc::init")
366	    };
367	
368	    // SAFETY: priv index in-range; no overlapping reference held.
369	    let pr: &mut Priv =
370	        unsafe { priv_slot_mut(STUB_C_PRIV_ID).expect("stub C priv slot in range") };
371	    pr.id = STUB_C_PRIV_ID;
372	    pr.proc_nr = Some(STUB_C_PROC_NR);
373	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
374	    pr.trap_mask = USR_T;
375	    pr.ipc_to.fill(0);
376	    set_sys_bit(&mut pr.ipc_to, system_priv_id);
377	    pr.k_call_mask.fill(0);
378	    set_call_bit(&mut pr.k_call_mask, (SYS_GETINFO - KERNEL_CALL) as usize);
379	    pr.notify_pending.fill(0);
380	    pr.asyn_pending.fill(0);
381	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
382	}
383	
384	/// Set the per-stub priv slot. `peer_priv_id` is the only target the
385	/// stub is permitted to send/notify (encoded as a single bit in `ipc_to`).
386	///
387	/// SAFETY: single-threaded boot; mutates only the priv slot at `id`.
388	unsafe fn install_one_stub_priv(id: PrivId, owner: ProcNr, peer_priv_id: PrivId) {
389	    // SAFETY: priv index in-range; no overlapping reference held.
390	    let pr: &mut Priv = unsafe {
391	        priv_slot_mut(id).expect("stub priv slot in range")
392	    };
393	    pr.id = id;
394	    pr.proc_nr = Some(owner);
395	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
396	    pr.trap_mask = SRV_T;
397	    pr.ipc_to.fill(0);
398	    set_sys_bit(&mut pr.ipc_to, peer_priv_id);
399	    pr.k_call_mask.fill(0);
400	    pr.notify_pending.fill(0);
401	    pr.asyn_pending.fill(0);
402	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
403	}
404	
405	fn populate_stub_slot(
406	    p: &mut Proc,
407	    nr: ProcNr,
408	    priv_id: PrivId,
409	    id: u8,
410	    entry_va: u64,
411	    stack_top: u64,
412	) {
413	    // Name: `id` followed by "stub\0..." padding. Lets the clock tick
414	    // handler print `name[0]` to identify which stub is running, while
415	    // `dump_tables` shows a recognizable per-stub string.
416	    p.name = [0; 16];
417	    p.name[0] = id;
418	    p.name[1] = b'-';
419	    p.name[2] = b's';
420	    p.name[3] = b't';
421	    p.name[4] = b'u';
422	    p.name[5] = b'b';
423	
424	    p.nr = nr;
425	    p.endpoint = boot_endpoint(nr);
426	    p.priv_id = Some(priv_id);
427	    p.priority = crate::proc::table::SRV_Q;
428	    // 5 ticks per quantum = 50 ms at 100 Hz. Short enough to see frequent
429	    // A/B switches in the boot demo, long enough that the do_ipc trace
430	    // (one line per 100 SVCs) still gets a few samples per burst.
431	    p.quantum_ms = 5;
432	    p.quantum_left = p.quantum_ms as u64;
433	
434	    // EL0 entry state.
435	    p.regs.elr_el1 = entry_va;
436	    p.regs.sp_el0 = stack_top;
437	    p.regs.spsr_el1 = STUB_SPSR_EL0;
438	
439	    // Run-queue link starts cleared — `sched::enqueue` will set it.
440	    p.next_ready = None;
441	
442	    // Mark runnable.
443	    p.rts_flags.store(0, Ordering::Relaxed);
444	}
445	
446	/// Translate a kernel-image VA to PA via Limine's kernel-address response.
447	fn kernel_pa_of(va: u64) -> u64 {
448	    kernel_va_to_pa(va).expect(
449	        "Limine did not populate the kernel-address response — bootloader too old?",
450	    )
451	}
