148	}
149	
150	/// Verify Limine programmed TCR_EL1's TTBR0-side walk structure the way our
151	/// page-table math assumes: 48-bit VA (T0SZ=16) so the walk has 4 levels,
152	/// and 4 KiB granule (TG0=0) so `pte_index` shifts by 12+9*… correctly.
153	/// IRGN0/ORGN0/SH0 are perf-only on single-core slice 2.3 and are reported
154	/// in the panic message but not enforced; `activate_user_ttbr0` leaves them
155	/// as Limine set them.
156	pub fn assert_tcr_el1_ttbr0_ready() {
157	    let tcr: u64;
158	    // SAFETY: TCR_EL1 is readable at EL1; no side effects.
159	    unsafe {
160	        asm!("mrs {0}, tcr_el1", out(reg) tcr, options(nomem, nostack, preserves_flags));
161	    }
