163	    let t0sz = tcr & 0x3F;
164	    let tg0 = (tcr >> 14) & 0x3;
165	    let irgn0 = (tcr >> 8) & 0x3;
166	    let orgn0 = (tcr >> 10) & 0x3;
167	    let sh0 = (tcr >> 12) & 0x3;
168	
169	    assert!(
170	        t0sz == 16 && tg0 == 0b00,
171	        "TCR_EL1 = {tcr:#018x} (T0SZ={t0sz} TG0={tg0} IRGN0={irgn0} ORGN0={orgn0} SH0={sh0}); \
