175	
176	/// Install `root_pa` as TTBR0_EL1 and ensure TTBR0 walks are enabled.
177	///
178	/// `assert_tcr_el1_ttbr0_ready` has already confirmed that Limine programmed
179	/// the structural TTBR0 fields (T0SZ=16, TG0=4 KiB) to match our walker, so
180	/// here we only need to clear EPD0 if set. We deliberately read-modify-write
181	/// just bit 7 — touching any other TCR field risks perturbing TTBR1, which
182	/// Limine owns and whose translations the kernel is actively using.
183	///
184	/// SAFETY: must be called with interrupts masked. `root_pa` must point at a
185	/// valid L0 page table.
186	pub unsafe fn activate_user_ttbr0(root_pa: u64) {
187	    const TCR_EPD0: u64 = 1 << 7;
188	
189	    // SAFETY: TTBR0_EL1, TCR_EL1, and TLB-maintenance ops are EL1-only and
190	    // touch no normal memory. Bit 7 (EPD0) is the only TCR field we
191	    // perturb; the rest stays as Limine left it.
192	    unsafe {
193	        let tcr: u64;
194	        asm!("mrs {0}, tcr_el1", out(reg) tcr, options(nomem, nostack, preserves_flags));
195	        let new_tcr = tcr & !TCR_EPD0;
196	
197	        asm!(
198	            "msr ttbr0_el1, {root}",
199	            "msr tcr_el1, {tcr}",
200	            "isb",
201	            "tlbi vmalle1",
202	            "dsb ish",
203	            "isb",
204	            root = in(reg) root_pa,
205	            tcr = in(reg) new_tcr,
206	            options(nomem, nostack, preserves_flags),
207	        );
208	    }
209	}
210	
211	/// Make instruction memory coherent with a recent data write at `va..va+len`.
212	///
213	/// AArch64 caches are PIPT for data but VIPT-flavored for instructions; after
214	/// writing into a code page we must clean the data side to PoU, then
215	/// invalidate the i-cache. Sequence is straight out of the ARM ARM §B2.4
216	/// example.
217	///
218	/// SAFETY: `va..va+len` must be a valid mapped range readable at EL1.
219	pub unsafe fn flush_icache_range(va: u64, len: usize) {
220	    // CTR_EL0.DminLine (bits 19:16) = log2 of the minimum D-cache line
221	    // size in words; multiply by the 4 B word size to get bytes. QEMU virt
222	    // reports 64 here; Apple Silicon reports 128.
223	    let ctr: u64;
224	    // SAFETY: CTR_EL0 is readable at EL1; no side effects.
225	    unsafe {
226	        asm!("mrs {0}, ctr_el0", out(reg) ctr, options(nomem, nostack, preserves_flags));
227	    }
228	    let line_bytes = 4_u64 << ((ctr >> 16) & 0xF);
229	
230	    let mut p = va & !(line_bytes - 1);
231	    let end = va + len as u64;
232	    while p < end {
233	        // SAFETY: `dc cvau` / `ic ivau` are EL0-permissive cache ops on a
234	        // VA already known to be mapped; no memory access semantically.
235	        unsafe {
236	            asm!("dc cvau, {0}", in(reg) p, options(nostack, preserves_flags));
237	        }
238	        p += line_bytes;
239	    }
240	    // SAFETY: barrier + i-cache invalidation; no memory access.
241	    unsafe {
242	        asm!(
243	            "dsb ish",
244	            "ic iallu",
245	            "dsb ish",
246	            "isb",
247	            options(nomem, nostack, preserves_flags),
248	        );
249	    }
250	}
