38	#[unsafe(no_mangle)]
39	extern "C" fn kmain() -> ! {
40	    // Resolve the UART MMIO virtual address before any output. Limine maps
41	    // PL011 into the HHDM (under base revision 2, the [0, 4 GiB) blanket
42	    // map covers device memory); we fall back to the physical address if
43	    // the bootloader didn't populate the response.
44	    let hhdm = arch::limine_hhdm_offset().unwrap_or(0);
45	    arch::set_uart_base(hhdm as usize + arch::PL011_PHYS_BASE);
46	
47	    arch::init();
48	
49	    let mut con = uart::Uart::new();
50	    let _ = writeln!(con, "MINIX 4 booting on aarch64");
51	
52	    if arch::limine_base_revision_supported() {
53	        let _ = writeln!(con, "HHDM offset: {hhdm:#018x}");
54	    } else {
55	        let _ = writeln!(
56	            con,
57	            "Limine base revision unsupported (loader is too old)"
58	        );
59	    }
60	
61	    proc::init();
62	    let _ = writeln!(con);
63	    let _ = proc::dump_tables(&mut con);
64	
65	    // Slice 3.1a: capture Limine's HHDM offset and populate the physical
66	    // frame allocator from the memmap. Both are prerequisites for the
67	    // address-space API (`arch::aarch64::addrspace::AddrSpace`).
68	    // SAFETY: single-threaded boot; this is the only writer of HHDM_OFFSET
