120	fn mm_smoke_test(con: &mut uart::Uart) {
121	    use arch::aarch64::addrspace::{AddrSpace, Prot};
122	
123	    let _ = writeln!(con, "\n[mm] smoke test starting");
124	
125	    // Track the four (VA, PA) pairs we install so we can re-verify after
126	    // re-walking.
