134	    // exercised across multiple intermediate-table allocations.
135	    let test_vas: [u64; 4] = [
136	        0x0000_0000_0080_0000,
137	        0x0000_0000_0090_0000,
138	        0x0000_0001_0000_0000,
139	        0x0000_0040_0000_0000,
140	    ];
141	
142	    for (i, &va) in test_vas.iter().enumerate() {
143	        let frame = mm::alloc_frame().expect("smoke: alloc_frame ran out");
144	        let pa = frame.addr();
145	        aspace
146	            .map_page(va, pa, Prot::RW_DATA)
147	            .unwrap_or_else(|e| panic!("map_page({va:#x}) failed: {e:?}"));
148	        mappings[i] = (va, pa);
149	    }
150	    let _ = writeln!(con, "[mm] map OK (4 mappings installed)");
151	
152	    for (va, expected_pa) in mappings.iter() {
153	        let got = aspace
154	            .walk_pt(*va)
155	            .unwrap_or_else(|| panic!("walk_pt({va:#x}) returned None"));
156	        assert!(
157	            got == *expected_pa,
158	            "walk_pt({va:#x}) returned {got:#x}, expected {expected_pa:#x}",
159	        );
160	    }
161	    // Negative case: walking an unmapped VA must return None.
162	    let unmapped = 0x0000_0000_0000_8000;
163	    assert!(
164	        aspace.walk_pt(unmapped).is_none(),
165	        "walk_pt({unmapped:#x}) returned Some for an unmapped VA"
166	    );
167	    let _ = writeln!(con, "[mm] walk OK (all 4 mappings + 1 unmapped check)");
168	
169	    // Leaf frames live outside the AddrSpace's ownership — free them
170	    // explicitly (the AddrSpace only owns the L0/L1/L2/L3 tree).
171	    for (_va, pa) in mappings.iter() {
172	        mm::free_frame(mm::Frame::from_addr(*pa));
173	    }
174	
175	    aspace.destroy();
176	
177	    // `destroy()` frees the L0 root last; the free list is LIFO so the
178	    // next `alloc_frame` must return that same PA. Confirms the
179	    // free-list path is hot (rather than alloc still bumping fresh
180	    // frames out of the region).
181	    let reused = mm::alloc_frame().expect("smoke: no frame returned after free");
182	    let reused_pa = reused.addr();
183	    assert!(
184	        reused_pa == l0_pa,
185	        "smoke: expected free-list reuse of L0 PA {l0_pa:#x}, got {reused_pa:#x}",
186	    );
187	    // Return it so the free list inherits a non-empty state for the next
188	    // slice; the bump regions are never repopulated by `free_frame`, so
189	    // the frame would otherwise sit idle outside the allocator's reach.
190	    mm::free_frame(reused);
191	
192	    let _ = writeln!(con, "[mm] free OK (destroy + reuse verified)");
193	}
