1	//! Physical frame allocator — 4 KiB granule, intrusive free list + per-region
2	//! bump pointers seeded from Limine's memmap.
3	//!
4	//! The allocator's state is just two pieces:
5	//!  - a `[Region; MAX_REGIONS]` array of `(base_pa, next_free_pa, end_pa)`
6	//!    bump pointers, one per `MEMMAP_USABLE` region Limine reported. `base_pa`
7	//!    is kept after init so `free_frame` can bounds-check freed PAs against
8	//!    the *original* extent, not the post-bump remainder;
9	//!  - a single free-list head pointer (kernel virtual address, HHDM-relative)
10	//!    of recently-freed frames.
11	//!
12	//! Allocation prefers the free list; if empty, bumps the first region with
13	//! room. Freed frames are pushed onto the free list — each frame's first
14	//! 8 bytes hold a pointer to the next free frame (the classic intrusive
15	//! free-list trick). This means each frame must be at least 8 bytes — which
16	//! is trivially true at 4 KiB.
17	//!
18	//! Capacity: MAX_REGIONS = 16 is enough for QEMU virt aarch64 (typically
19	//! 2–3 USABLE regions) and Apple Silicon QEMU (similar). If a board ever
20	//! reports more, `init_from_limine_memmap` panics with a clear message
21	//! pointing at this constant.
22	//!
23	//! Concurrency: single-threaded boot. The allocator is wrapped in an
24	//! `UnsafeCell` newtype with `unsafe impl Sync`, matching the convention
25	//! documented on [`crate::proc::table`]. Phase 3.2+'s page-fault flow runs
26	//! the allocator outside fault context — the handler sets `RTS_PAGEFAULT`
27	//! and returns to the scheduler, which then runs VM (or the kernel
28	//! resolver), which calls the allocator. The allocator therefore never
29	//! re-enters from an IRQ or fault.
30	
31	use core::cell::UnsafeCell;
32	use core::ptr;
33	
34	use crate::arch::aarch64::limine::{MEMMAP_USABLE, memmap_entries};
35	
36	/// 4 KiB page / frame size, in bytes.
37	pub const FRAME_SIZE: usize = 4096;
38	
39	/// Maximum number of `MEMMAP_USABLE` regions the allocator can track.
40	const MAX_REGIONS: usize = 16;
41	
42	/// Identifies one 4 KiB physical frame by its page-frame number (PA >> 12).
43	#[derive(Copy, Clone, PartialEq, Eq, Debug)]
44	pub struct Frame(u64);
45	
46	impl Frame {
47	    /// Construct from a physical address. The address must be 4 KiB-aligned
48	    /// — non-aligned values are rejected at construction so downstream
49	    /// callers can rely on `frame.addr()` returning an aligned PA.
50	    pub const fn from_addr(pa: u64) -> Self {
51	        assert!(pa & (FRAME_SIZE as u64 - 1) == 0, "Frame::from_addr: PA not 4 KiB aligned");
52	        Self(pa >> 12)
53	    }
54	
55	    /// Physical address of this frame.
56	    pub const fn addr(self) -> u64 {
57	        self.0 << 12
58	    }
59	}
60	
61	#[derive(Copy, Clone)]
62	struct Region {
63	    /// First PA in this region, captured at init time. Stays fixed for the
64	    /// life of the allocator so `free_frame` can check `base_pa <= pa`
65	    /// against the region's *original* extent — `next_free_pa` advances on
66	    /// every bump, so it can't double as the lower bound.
67	    base_pa: u64,
68	    /// Next PA to hand out from this region; equals `base_pa` until the
69	    /// first allocation, then advances toward `end_pa`.
70	    next_free_pa: u64,
71	    /// One-past-the-last PA in this region.
72	    end_pa: u64,
73	}
74	
75	const EMPTY_REGION: Region = Region {
76	    base_pa: 0,
77	    next_free_pa: 0,
78	    end_pa: 0,
79	};
80	
81	struct Allocator {
82	    regions: [Region; MAX_REGIONS],
83	    region_count: usize,
84	    /// Head of the free list, as an HHDM virtual address (so we can deref
85	    /// it directly without redoing the HHDM math on each `alloc_frame`).
86	    /// `null` means the free list is empty.
87	    free_head: *mut FreeNode,
88	    /// Statistics for diagnostics — incremented on every alloc/free.
89	    allocs: u64,
90	    frees: u64,
91	}
92	
93	#[repr(C)]
94	struct FreeNode {
95	    next: *mut FreeNode,
96	}
97	
98	#[repr(transparent)]
99	struct AllocatorCell(UnsafeCell<Allocator>);
100	// SAFETY: single-threaded boot invariant; see module-level comment.
101	unsafe impl Sync for AllocatorCell {}
102	
103	static ALLOC: AllocatorCell = AllocatorCell(UnsafeCell::new(Allocator {
104	    regions: [EMPTY_REGION; MAX_REGIONS],
105	    region_count: 0,
106	    free_head: ptr::null_mut(),
107	    allocs: 0,
108	    frees: 0,
109	}));
110	
111	/// Populate the allocator from Limine's memmap. Must be called once during
112	/// boot, before any [`alloc_frame`] / [`free_frame`] call.
113	///
114	/// `hhdm_offset` is Limine's HHDM offset (also passed to
115	/// [`crate::mm::set_hhdm_offset`] separately so the allocator can dereference
116	/// freed-frame pointers into a kernel VA).
117	///
118	/// SAFETY: must be called exactly once, single-threaded, after
119	/// [`crate::mm::set_hhdm_offset`].
120	pub unsafe fn init_from_limine_memmap() {
121	    let entries =
122	        memmap_entries().expect("Limine did not populate the memmap response");
123	
124	    // SAFETY: single-threaded boot, single writer.
125	    let a = unsafe { &mut *ALLOC.0.get() };
126	
127	    for entry in entries {
128	        if entry.kind != MEMMAP_USABLE {
129	            continue;
130	        }
131	        // Limine guarantees USABLE entries are 4 KiB-aligned in both base
132	        // and length — verify rather than silently dropping bytes.
133	        let base = entry.base;
134	        let len = entry.length;
135	        assert!(
136	            base & (FRAME_SIZE as u64 - 1) == 0,
137	            "Limine USABLE base {base:#x} is not 4 KiB-aligned"
138	        );
139	        assert!(
140	            len & (FRAME_SIZE as u64 - 1) == 0,
141	            "Limine USABLE length {len:#x} is not 4 KiB-aligned"
142	        );
143	        if len == 0 {
144	            continue;
145	        }
146	        assert!(
147	            a.region_count < MAX_REGIONS,
148	            "Limine reported more than MAX_REGIONS={MAX_REGIONS} usable regions; \
149	             grow the constant in mm::frame"
150	        );
151	        a.regions[a.region_count] = Region {
152	            base_pa: base,
153	            next_free_pa: base,
154	            end_pa: base.checked_add(len).expect("USABLE region overflows u64"),
155	        };
156	        a.region_count += 1;
157	    }
158	
159	    assert!(
160	        a.region_count > 0,
161	        "Limine memmap contains no MEMMAP_USABLE regions"
162	    );
163	}
164	
165	/// Allocate one 4 KiB frame. Returns `None` if no physical memory remains
166	/// (both the free list and every bump region are exhausted).
167	pub fn alloc_frame() -> Option<Frame> {
168	    // SAFETY: single-threaded boot invariant; see module-level comment.
169	    let a = unsafe { &mut *ALLOC.0.get() };
170	
171	    // Free list takes priority — recently freed frames are still cache-hot.
172	    if !a.free_head.is_null() {
173	        // SAFETY: free_head is either null or an HHDM-VA pointer we set on a
174	        // previous `free_frame`. Reading the first 8 bytes of a free frame
175	        // through HHDM is sound because the frame is unmapped from all
176	        // address spaces (free means free) and HHDM is the only mapping.
177	        let node = a.free_head;
178	        let next = unsafe { (*node).next };
179	        a.free_head = next;
180	        a.allocs += 1;
181	        let pa = hhdm_vaddr_to_pa(node as u64);
182	        return Some(Frame::from_addr(pa));
183	    }
184	
185	    // Otherwise bump from the first region with room.
186	    for r in &mut a.regions[..a.region_count] {
187	        if r.next_free_pa < r.end_pa {
188	            let pa = r.next_free_pa;
189	            r.next_free_pa += FRAME_SIZE as u64;
190	            a.allocs += 1;
191	            // Zero the frame on first hand-out. Page-table walkers expect
192	            // intermediate tables to start all-invalid, and zero pages are
193	            // what user-mode brk/mmap expects too. Cost: one 4 KiB memset,
194	            // amortized over the frame's lifetime.
195	            // SAFETY: HHDM covers this PA (Limine base revision 2 blanket-maps
196	            // [0, 4 GiB)), the frame is exclusively ours, and HHDM is
197	            // cacheable normal memory — no MMIO side-channel that would
198	            // require `write_volatile`.
199	            unsafe {
200	                ptr::write_bytes(crate::mm::phys_to_hhdm(pa), 0, FRAME_SIZE);
201	            }
202	            return Some(Frame::from_addr(pa));
203	        }
204	    }
205	    None
206	}
207	
208	/// Return one 4 KiB frame to the allocator. The frame is pushed onto the
209	/// free list; future `alloc_frame` calls will hand it back out (zeroed —
210	/// we re-zero on the alloc side, not the free side, so callers can free
211	/// without thinking about residual state).
212	///
213	/// Panics if `frame` lies outside the union of all tracked regions — that
214	/// would mean a caller forged a frame from a non-USABLE PA (e.g. a kernel-image
215	/// PA from `EXECUTABLE_AND_MODULES`, or a gap between two USABLE regions).
216	///
217	/// **Precondition (not checked):** the same frame must not be freed twice.
218	/// A double free silently corrupts the free list — the intrusive `next`
219	/// pointer on the freed frame gets overwritten with the previous head, and
220	/// the next two `alloc_frame` calls hand out the same PA. Detecting at
221	/// runtime would require an O(n) free-list walk per free (or extra
222	/// per-frame state); both are overkill for a single-threaded boot
223	/// allocator. The bounds check below catches forged-PA cases but cannot
224	/// distinguish a legitimate frame from one already on the list.
225	pub fn free_frame(frame: Frame) {
226	    let pa = frame.addr();
227	
228	    // SAFETY: single-threaded boot invariant.
229	    let a = unsafe { &mut *ALLOC.0.get() };
230	
231	    // Bounds-check against tracked regions. `base_pa` is captured at init
232	    // time and never advances, so `[base_pa, end_pa)` is the region's
233	    // original extent — exactly the set of legal frame PAs.
234	    let mut in_range = false;
235	    for r in &a.regions[..a.region_count] {
236	        if r.base_pa <= pa && pa < r.end_pa {
237	            in_range = true;
238	            break;
239	        }
240	    }
241	    assert!(in_range, "free_frame: PA {pa:#x} is outside all USABLE regions");
242	
243	    // Push onto the free list via HHDM.
244	    let vaddr = crate::mm::phys_to_hhdm(pa) as *mut FreeNode;
245	    // SAFETY: the frame is now owned by the allocator (caller relinquishes
246	    // it). HHDM mapping guarantees the VA is readable+writable.
247	    unsafe {
248	        (*vaddr).next = a.free_head;
249	    }
250	    a.free_head = vaddr;
251	    a.frees += 1;
252	}
253	
254	fn hhdm_vaddr_to_pa(vaddr: u64) -> u64 {
255	    // HHDM is a flat shift; reversing is sub.
256	    vaddr - crate::mm::hhdm_offset()
257	}
258

