```rust
pub unsafe fn userland_bootstrap() {
    use crate::arch::aarch64::asid::alloc_asid;
    use crate::arch::aarch64::addrspace::{AddrSpace, Prot};
    use crate::arch::aarch64::mmu::{self, enable_ttbr0_walks_once};
    use crate::mm::{Frame, alloc_frame, phys_to_hhdm};

    // 1. Sanity-check MMU invariants Limine handed us.
    mmu::assert_mair_normal_wb();
    mmu::assert_tcr_el1_ttbr0_ready(); // now also asserts AS=0

    // 2. Clear TCR_EL1.EPD0 once; per-proc TTBR0 install happens at every
    //    context switch via `proc::sched::schedule_next`.
    // SAFETY: DAIF still masked from Limine handoff; single-threaded boot.
    unsafe { enable_ttbr0_walks_once() };

    // 3. Build each stub.
    // SAFETY: single-threaded boot; build_stub touches only its caller-
    // owned AddrSpace + the named proc slot.
    unsafe {
        build_stub(
            STUB_A_PROC_NR, STUB_A_PRIV_ID, b'A',
            &_user_stub_a_start, &_user_stub_a_end,
            USER_CODE_VA_A, USER_STACK_VA_A,
        );
        build_stub(
            STUB_B_PROC_NR, STUB_B_PRIV_ID, b'B',
            &_user_stub_b_start, &_user_stub_b_end,
            USER_CODE_VA_B, USER_STACK_VA_B,
        );
        build_stub(
            STUB_C_PROC_NR, STUB_C_PRIV_ID, b'C',
            &_user_stub_c_start, &_user_stub_c_end,
            USER_CODE_VA_C, USER_STACK_VA_C,
        );
    }

    // 4. Install priv slots — unchanged from slice 2.6.
    // SAFETY: same.
    unsafe { install_stub_privs() };

    // 5. Enqueue all three on the scheduler.
    // SAFETY: same as today.
    unsafe {
        sched::enqueue(STUB_A_PROC_NR);
        sched::enqueue(STUB_B_PROC_NR);
        sched::enqueue(STUB_C_PROC_NR);
    }

    // 6. One-shot trace: dump per-proc (ttbr0_pa, asid) so the boot log
    //    proves each stub has a distinct AS.
    print_addrspace_summary();
}
```

`build_stub` body:

```rust
unsafe fn build_stub(
    nr: ProcNr,
    priv_id: PrivId,
    id: u8,
    stub_start: *const u8,
    stub_end: *const u8,
    code_va: u64,
    stack_va: u64,
) {
    use crate::arch::aarch64::addrspace::{AddrSpace, Prot};
    use crate::arch::aarch64::asid::alloc_asid;
    use crate::mm::{alloc_frame, phys_to_hhdm};

    // Per-proc page-table tree.
    let mut aspace = AddrSpace::new()
        .expect("AddrSpace::new failed during userland_bootstrap");
    let ttbr0_pa = aspace.ttbr0_pa;

    // Code frame: allocate, copy stub blob via HHDM, flush I-cache, map RO+X.
    let code_frame = alloc_frame()
        .expect("code frame alloc failed during userland_bootstrap");
    // SAFETY: stub_start..stub_end is rodata inside the kernel image; the
    // new code frame is exclusively ours and HHDM-mapped.
    unsafe {
        copy_stub_into_frame(code_frame, stub_start, stub_end);
    }
    aspace
        .map_page(code_va, code_frame.addr(), Prot::RO_CODE)
        .expect("map code page");

    // Stack frame: zeroed by `alloc_frame`, map RW+NX.
    let stack_frame = alloc_frame()
        .expect("stack frame alloc failed during userland_bootstrap");
    aspace
        .map_page(stack_va, stack_frame.addr(), Prot::RW_DATA)
        .expect("map stack page");

    // Hand the AddrSpace's L0 root over to the proc slot. We don't keep the
    // AddrSpace value around — slice 3.1b only needs the root PA; the
    // page-table tree is reachable via HHDM walks (slice 3.2+ uses this).
    let asid = unsafe { alloc_asid() };
    // SAFETY: single-threaded boot; sequential mutable borrow.
    unsafe {
        let p = proc_slot_mut(nr).expect("stub proc slot in range");
        populate_stub_slot(
            p, nr, priv_id, id, code_va, stack_va + PAGE_SIZE as u64,
            ttbr0_pa, asid,
        );
    }
    // Intentional: `aspace` goes out of scope here. `AddrSpace::destroy`
    // is *not* called — the page-table tree lives on inside the proc; the
    // ttbr0_pa stored in the slot is what makes it durable. Until slice
    // 3.2's exit/exec path lands, no AddrSpace is ever destroyed.
    core::mem::forget(aspace);
}

unsafe fn copy_stub_into_frame(
    frame: crate::mm::Frame,
    stub_start: *const u8,
    stub_end: *const u8,
) {
    // SAFETY: stub_end - stub_start non-negative by linker layout.
    let len = unsafe { stub_end.offset_from(stub_start) } as usize;
    assert!(len > 0 && len <= PAGE_SIZE);
    // SAFETY: frame is exclusively ours (just allocated, not yet mapped);
    // HHDM is the only mapping.
    unsafe {
        let dst = crate::mm::phys_to_hhdm(frame.addr()) as *mut u8;
        core::ptr::copy_nonoverlapping(stub_start, dst, len);
        crate::arch::aarch64::mmu::flush_icache_range(dst as u64, len);
    }
}
```

`populate_stub_slot` adds two parameters and two writes:

```rust
fn populate_stub_slot(
    p: &mut Proc,
    nr: ProcNr,
    priv_id: PrivId,
    id: u8,
    entry_va: u64,
    stack_top: u64,
    ttbr0_pa: u64,
    asid: u8,
) {
    // (existing body unchanged through `p.rts_flags.store(0, ...)`)

    p.ttbr0_pa = ttbr0_pa;
    p.asid = asid;
}
```

`print_addrspace_summary` is a small helper that walks proc slots A/B/C
and writes one line each:

```rust
fn print_addrspace_summary() {
    use core::fmt::Write;
    use crate::arch::aarch64::uart::Pl011;
    let mut uart = Pl011::new();
    let _ = writeln!(uart);
    for &nr in &[STUB_A_PROC_NR, STUB_B_PROC_NR, STUB_C_PROC_NR] {
        // SAFETY: single-threaded boot; sequential read-only borrow.
        let p = unsafe { proc_slot_mut(nr).expect("stub slot in range") };
        let _ = writeln!(
            uart,
            "[as] stub {} nr={:?} ttbr0_pa={:#x} asid={}",
            p.name[0] as char, p.nr, p.ttbr0_pa, p.asid,
        );
    }
}
```

(Pl011 directly, matching the `el0_sync_unexpected` precedent and the
exception-context UART pattern noted in research.)

