```rust
pub unsafe fn schedule_next() {
    let next_nr = match pick_proc() {
        Some(nr) => nr,
        None => return,
    };
    CURRENT_PROC_NR.store(next_nr.get(), Ordering::Relaxed);
    // SAFETY: next_nr came from the run queue; single-borrow.
    unsafe {
        let next = proc_slot_mut(next_nr).expect("schedule_next: next out of range");
        set_tpidr_to(next);
        crate::ipc::flush_deliver_msg(next);
    }
}
```

Edit to (note: TTBR0 swap is between `set_tpidr_to` and `flush_deliver_msg`
— the message flush writes via the active TTBR0, so the new proc's AS must
already be installed):

```rust
pub unsafe fn schedule_next() {
    let next_nr = match pick_proc() {
        Some(nr) => nr,
        None => return,
    };
    CURRENT_PROC_NR.store(next_nr.get(), Ordering::Relaxed);
    // SAFETY: next_nr came from the run queue; single-borrow.
    unsafe {
        let next = proc_slot_mut(next_nr).expect("schedule_next: next out of range");
        set_tpidr_to(next);
        // Per-proc TTBR0 + ASID install. Slice 3.1b: every runnable proc
        // is an EL0 stub with a real address space; assert that here so a
        // future slice that mistakenly enqueues a kernel task (asid=0) is
        // caught instead of silently using the previous proc's TTBR0.
        debug_assert!(
            next.ttbr0_pa != 0 && next.asid != 0,
            "schedule_next: proc {:?} has no AS (ttbr0_pa={:#x}, asid={})",
            next.nr, next.ttbr0_pa, next.asid,
        );
        crate::arch::aarch64::mmu::switch_ttbr0_with_asid(next.ttbr0_pa, next.asid);
        crate::ipc::flush_deliver_msg(next);
    }
}
```

