`build_stub` body:

```rust
unsafe fn build_stub(
    nr: ProcNr,
    priv_id: PrivId,
    id: u8,
    stub_start: *const u8,
    stub_end: *const u8,
    code_va: u64,
    stack_va: u64,
) {
    use crate::arch::aarch64::addrspace::{AddrSpace, Prot};
    use crate::arch::aarch64::asid::alloc_asid;
    use crate::mm::{alloc_frame, phys_to_hhdm};

    // Per-proc page-table tree.
    let mut aspace = AddrSpace::new()
        .expect("AddrSpace::new failed during userland_bootstrap");
    let ttbr0_pa = aspace.ttbr0_pa;

    // Code frame: allocate, copy stub blob via HHDM, flush I-cache, map RO+X.
    let code_frame = alloc_frame()
        .expect("code frame alloc failed during userland_bootstrap");
    // SAFETY: stub_start..stub_end is rodata inside the kernel image; the
    // new code frame is exclusively ours and HHDM-mapped.
    unsafe {
        copy_stub_into_frame(code_frame, stub_start, stub_end);
    }
    aspace
        .map_page(code_va, code_frame.addr(), Prot::RO_CODE)
        .expect("map code page");

    // Stack frame: zeroed by `alloc_frame`, map RW+NX.
    let stack_frame = alloc_frame()
        .expect("stack frame alloc failed during userland_bootstrap");
    aspace
        .map_page(stack_va, stack_frame.addr(), Prot::RW_DATA)
        .expect("map stack page");

    // Hand the AddrSpace's L0 root over to the proc slot. We don't keep the
    // AddrSpace value around — slice 3.1b only needs the root PA; the
    // page-table tree is reachable via HHDM walks (slice 3.2+ uses this).
    let asid = unsafe { alloc_asid() };
    // SAFETY: single-threaded boot; sequential mutable borrow.
    unsafe {
        let p = proc_slot_mut(nr).expect("stub proc slot in range");
        populate_stub_slot(
            p, nr, priv_id, id, code_va, stack_va + PAGE_SIZE as u64,
            ttbr0_pa, asid,
        );
    }
    // Intentional: `aspace` goes out of scope here. `AddrSpace::destroy`
    // is *not* called — the page-table tree lives on inside the proc; the
    // ttbr0_pa stored in the slot is what makes it durable. Until slice
    // 3.2's exit/exec path lands, no AddrSpace is ever destroyed.
    core::mem::forget(aspace);
}

unsafe fn copy_stub_into_frame(
    frame: crate::mm::Frame,
    stub_start: *const u8,
    stub_end: *const u8,
) {
    // SAFETY: stub_end - stub_start non-negative by linker layout.
    let len = unsafe { stub_end.offset_from(stub_start) } as usize;
    assert!(len > 0 && len <= PAGE_SIZE);
    // SAFETY: frame is exclusively ours (just allocated, not yet mapped);
    // HHDM is the only mapping.
    unsafe {
        let dst = crate::mm::phys_to_hhdm(frame.addr()) as *mut u8;
        core::ptr::copy_nonoverlapping(stub_start, dst, len);
        crate::arch::aarch64::mmu::flush_icache_range(dst as u64, len);
    }
}
```

