### Task 6 — Page-fault diagnostic decoder

**Files:** `kernel/src/arch/aarch64/exception.rs`

- [ ] **Step 1: Replace `el0_sync_unexpected` with a decoder.**

The current body extracts EC and ISS and panics. Extend with a match on
EC ∈ {0x20, 0x24}, decoding FSC + WnR + ISV:

```rust
#[unsafe(no_mangle)]
extern "C" fn el0_sync_unexpected(esr: u64, elr: u64, far: u64) -> ! {
    let mut uart = Pl011::new();
    let ec = (esr >> 26) & 0x3F;
    let iss = esr & 0xFF_FFFF;
    let _ = writeln!(uart);
    match ec {
        0x20 => {
            // Instruction abort, lower EL. ISS[5:0] = IFSC.
            let ifsc = iss & 0x3F;
            let _ = writeln!(uart, "!!! EL0 instruction abort (translation/permission)");
            let _ = writeln!(uart, "    IFSC = {:#04x} ({})", ifsc, fsc_name(ifsc));
        }
        0x24 => {
            // Data abort, lower EL. ISS[5:0]=DFSC, ISS[6]=WnR, ISS[24]=ISV.
            let dfsc = iss & 0x3F;
            let wnr  = (iss >> 6) & 1;
            let isv  = (iss >> 24) & 1;
            let _ = writeln!(uart, "!!! EL0 data abort (translation/permission)");
            let _ = writeln!(
                uart,
                "    DFSC = {:#04x} ({})  WnR = {}  ISV = {}",
                dfsc, fsc_name(dfsc), wnr, isv,
            );
        }
        _ => {
            let _ = writeln!(uart, "!!! unexpected EL0 sync exception (not SVC)");
        }
    }
    let _ = writeln!(
        uart,
        "    ESR_EL1  = {esr:#018x}  (EC = {ec:#04x}, ISS = {iss:#08x})",
    );
    let _ = writeln!(uart, "    ELR_EL1  = {elr:#018x}  FAR_EL1  = {far:#018x}");
    panic!("EL0 sync exception: EC={ec:#x} ESR_EL1={esr:#x}");
}

/// Tiny FSC-name decoder. Covers the codes slice 3.1b stubs would actually
/// hit on a fresh AS. The full table (ARM ARM D13.2.40) has ~30 codes; we
/// just want to make boot-log triage tractable.
fn fsc_name(fsc: u64) -> &'static str {
    match fsc {
        0x04 => "translation fault, L0",
        0x05 => "translation fault, L1",
        0x06 => "translation fault, L2",
        0x07 => "translation fault, L3",
        0x09 => "access flag fault, L1",
        0x0A => "access flag fault, L2",
        0x0B => "access flag fault, L3",
        0x0D => "permission fault, L1",
        0x0E => "permission fault, L2",
        0x0F => "permission fault, L3",
        0x21 => "alignment fault",
        _ => "other",
    }
}
```

Note: still ends in `panic!` — slice 3.1b is a diagnostic upgrade only. Real
recovery (page-fault → VM, brk pages, etc) lands in 3.2 / 3.4.

