```rust
/// Clear `TCR_EL1.EPD0` so the MMU starts walking TTBR0 on EL0 accesses.
/// Limine leaves EPD0 set by default; until this runs, every EL0 address
/// access translation-faults. Must be called exactly once during
/// `userland_bootstrap`, before any proc is enqueued onto the scheduler.
///
/// SAFETY: must be called with DAIF masked at EL1, single-threaded boot.
pub unsafe fn enable_ttbr0_walks_once() {
    const TCR_EPD0: u64 = 1 << 7;
    // SAFETY: caller's invariants. Only bit 7 of TCR_EL1 is touched; the
    // TTBR1-side fields (which the kernel's own translation regime relies
    // on) are read-modify-write-preserved.
    unsafe {
        let tcr: u64;
        core::arch::asm!(
            "mrs {0}, tcr_el1",
            out(reg) tcr,
            options(nomem, nostack, preserves_flags),
        );
        let new_tcr = tcr & !TCR_EPD0;
        core::arch::asm!(
            "msr tcr_el1, {0}",
            "isb",
            in(reg) new_tcr,
            options(nomem, nostack, preserves_flags),
        );
    }
}
```

- [ ] **Step 3: Add `switch_ttbr0_with_asid`.**

```rust
/// Install a per-proc TTBR0 + ASID and invalidate stale TLB entries for
/// that ASID. Called from `proc::sched::schedule_next` on every EL1 → EL0
/// transition that picks a proc with `ttbr0_pa != 0`.
///
/// `ttbr0_pa` is the L0-root PA, frame-aligned. `asid` is in [1, 255];
/// caller is responsible for sourcing it from `arch::aarch64::asid::alloc_asid`.
///
/// The TLBI is unconditional. With three ASIDs in slice 3.1b, the cost is
/// negligible (~tens of cycles per switch on QEMU) and the simpler control
/// flow is worth more than micro-optimization; a later slice can elide it
/// once an "AS already activated" flag is added.
///
/// SAFETY: must be called with DAIF masked at EL1. `ttbr0_pa` must point
/// at a valid L0 page table the caller owns.
pub unsafe fn switch_ttbr0_with_asid(ttbr0_pa: u64, asid: u8) {
    debug_assert!(asid != 0, "switch_ttbr0_with_asid: ASID 0 is reserved");
    debug_assert!(
        ttbr0_pa & (PAGE_SIZE as u64 - 1) == 0,
        "switch_ttbr0_with_asid: ttbr0_pa not page-aligned",
    );
    let tagged = ttbr0_pa | ((asid as u64) << 48);
    // SAFETY: TTBR0_EL1 + TLBI ASIDE1 are EL1 ops; no normal-memory access.
    // The ISB after MSR ensures the new TTBR0 is observed before the TLBI;
    // the DSB ISH after the TLBI ensures the invalidate completes before
    // the trailing ISB makes the eret context-synchronize.
    unsafe {
        core::arch::asm!(
            "msr ttbr0_el1, {ttbr}",
            "isb",
            "tlbi aside1, {asid_x}",
            "dsb ish",
            "isb",
            ttbr = in(reg) tagged,
            asid_x = in(reg) (asid as u64) << 48,
            options(nomem, nostack, preserves_flags),
        );
    }
}
```

Note: `tlbi aside1, Xt` takes the ASID in bits [63:48] of Xt (the rest are
RES0 / SBZ) — same encoding the TLBI op reads, so we shift by 48.

